public OngoingInjecter filterCandidate(final Collection<Object> mocks, final Field field, final Object fieldInstance) {
    if (mocks == null || mocks.size() != 1 || field == null || fieldInstance == null) {
        return new OngoingInjecter() {
            public boolean thenInject() {
                return false;
            }
        };
    }

    final Object matchingMock = mocks.iterator().next();

    return new OngoingInjecter() {
        public boolean thenInject() {
            try {
                if (!tryPropertySetter(fieldInstance, field, matchingMock)) {
                    new FieldSetter(fieldInstance, field).set(matchingMock);
                }
                return true;
            } catch (Exception e) {
                throw new MockitoException("Problems injecting dependency in " + field.getName(), e);
            }
        }
    };
}

private boolean tryPropertySetter(Object instance, Field field, Object value) throws Exception {
    if (instance == null || field == null || value == null) {
        return false;
    }
    String setterName = "set" + capitalize(field.getName());
    java.lang.reflect.Method setterMethod = null;
    try {
        setterMethod = instance.getClass().getMethod(setterName, field.getType());
    } catch (NoSuchMethodException e) {
        return false;
    }
    setterMethod.invoke(instance, value);
    return true;
}

private String capitalize(String name) {
    if (name == null || name.length() == 0) {
        return name;
    }
    return name.substring(0, 1).toUpperCase() + name.substring(1);
}
